import heroImage from "../assets/images/main.svg";

export default function Hero() {
    return (
        <div className="container-fluid">
            <div className="card border-0 overflow-hidden">
                <div className="card-header d-md-flex align-items-center border-bottom-0 bg-transparent p-5">
                    <img src={heroImage} alt="gambar hero" id="hero-image" className="rounded-3"/>
                    <p>Writer. Video maker. Flâneuse.</p>
                    <p className="ms-3 mt-md-0 mt-2 text-center display-6 text-semi-warning">
                        Searching for magic in between the cracks of ordinary objects.
                    </p>
                </div>
            </div>
        </div>
    )
}
